import sys
sys.path.insert(0, "src")
from assay_engine.provenance import ProvenanceTrail, ProvenanceError

def check(label, fn):
    try: fn(); print(f"{label}: handled")
    except ProvenanceError: print(f"{label}: ProvenanceError (good)")
    except Exception as e: print(f"{label}: *** RAW {type(e).__name__}: {e} ***")

# evidence raises in dict()
class E1:
    gate="g"; approved=True; reason="r"
    @property
    def evidence(self): raise RuntimeError("boom-ev")
check("evidence raises", lambda: ProvenanceTrail().as_recorder()(E1()))

# evidence is non-mapping non-None -> dict(x) raises
class E2:
    gate="g"; approved=True; reason="r"; evidence=12345
check("evidence is int", lambda: ProvenanceTrail().as_recorder()(E2()))

# gate is unhashable / weird type that breaks record's freeze? gate goes into payload
class E3:
    approved=True; reason="r"; evidence={}
    @property
    def gate(self): return [1,2,3]  # list gate
check("gate is list", lambda: ProvenanceTrail().as_recorder()(E3()))

# reason is an object whose str fails? reason stored raw in payload
class BadStr:
    def __str__(self): raise ValueError("nostr")
    __hash__=None
class E4:
    gate="g"; approved=True; reason=BadStr(); evidence={}
check("reason unhashable", lambda: ProvenanceTrail().as_recorder()(E4()))

# evidence has unhashable value -> freeze in record raises
class E5:
    gate="g"; approved=True; reason="r"
    evidence={"k": (lambda:0)}  # function leaf, hashable actually; use set of list
class E6:
    gate="g"; approved=True; reason="r"
    evidence={"k": [{1,2}]}  # nested fine
import datetime
class Unh:
    __hash__=None
class E7:
    gate="g"; approved=True; reason="r"
    evidence={"k": Unh()}
check("evidence unhashable leaf", lambda: ProvenanceTrail().as_recorder()(E7()))
EOF
